import React, { useState, useEffect } from 'react';
import { createRoot } from 'react-dom/client';

const CONFIG = {
  authorizationEndpoint: 'https://your-auth-server.com/oauth/authorize',
  clientId: 'your-client-id',
  redirectUri: window.location.origin + '/callback',
  scope: 'openid profile email',
  responseType: 'token'
};

const generateRandomString = (length) => {
  const array = new Uint8Array(length);
  window.crypto.getRandomValues(array);
  return Array.from(array, byte => byte.toString(16).padStart(2, '0')).join('');
};

const sha256 = async (plain) => {
  const encoder = new TextEncoder();
  const data = encoder.encode(plain);
  const hash = await window.crypto.subtle.digest('SHA-256', data);
  return Array.from(new Uint8Array(hash))
    .map(b => b.toString(16).padStart(2, '0'))
    .join('');
};

const base64URLEncode = (str) => {
  return btoa(String.fromCharCode.apply(null, 
    str.split('').map(c => c.charCodeAt(0))))
    .replace(/\+/g, '-')
    .replace(/\//g, '_')
    .replace(/=/g, '');
};

const AuthService = {
  async initiateAuth() {
    const state = generateRandomString(32);
    const nonce = generateRandomString(32);
    
    sessionStorage.setItem('oauth_state', state);
    sessionStorage.setItem('oauth_nonce', nonce);
    sessionStorage.setItem('auth_timestamp', Date.now().toString());
    
    const params = new URLSearchParams({
      response_type: CONFIG.responseType,
      client_id: CONFIG.clientId,
      redirect_uri: CONFIG.redirectUri,
      scope: CONFIG.scope,
      state: state,
      nonce: nonce
    });
    
    window.location.href = `${CONFIG.authorizationEndpoint}?${params.toString()}`;
  },

  parseCallback() {
    const hash = window.location.hash.substring(1);
    const params = new URLSearchParams(hash);
    
    const accessToken = params.get('access_token');
    const tokenType = params.get('token_type');
    const expiresIn = params.get('expires_in');
    const state = params.get('state');
    const error = params.get('error');
    const errorDescription = params.get('error_description');
    
    if (error) {
      throw new Error(`OAuth Error: ${error} - ${errorDescription || 'Unknown error'}`);
    }
    
    const storedState = sessionStorage.getItem('oauth_state');
    const authTimestamp = sessionStorage.getItem('auth_timestamp');
    
    if (!storedState || state !== storedState) {
      sessionStorage.removeItem('oauth_state');
      sessionStorage.removeItem('oauth_nonce');
      sessionStorage.removeItem('auth_timestamp');
      throw new Error('State mismatch - possible CSRF attack');
    }
    
    if (authTimestamp) {
      const elapsed = Date.now() - parseInt(authTimestamp);
      if (elapsed > 600000) {
        sessionStorage.removeItem('oauth_state');
        sessionStorage.removeItem('oauth_nonce');
        sessionStorage.removeItem('auth_timestamp');
        throw new Error('Authentication timeout');
      }
    }
    
    sessionStorage.removeItem('oauth_state');
    sessionStorage.removeItem('auth_timestamp');
    
    if (!accessToken) {
      throw new Error('No access token received');
    }
    
    window.history.replaceState({}, document.title, window.location.pathname);
    
    return {
      accessToken,
      tokenType,
      expiresIn: expiresIn ? parseInt(expiresIn) : null,
      nonce: sessionStorage.getItem('oauth_nonce')
    };
  },

  storeToken(tokenData) {
    const expiresAt = tokenData.expiresIn 
      ? Date.now() + (tokenData.expiresIn * 1000)
      : Date.now() + (3600 * 1000);
    
    const tokenInfo = {
      accessToken: tokenData.accessToken,
      tokenType: tokenData.tokenType,
      expiresAt: expiresAt,
      nonce: tokenData.nonce
    };
    
    sessionStorage.setItem('token_info', JSON.stringify(tokenInfo));
    sessionStorage.removeItem('oauth_nonce');
  },

  getToken() {
    const tokenInfoStr = sessionStorage.getItem('token_info');
    if (!tokenInfoStr) return null;
    
    const tokenInfo = JSON.parse(tokenInfoStr);
    
    if (Date.now() >= tokenInfo.expiresAt) {
      this.clearToken();
      return null;
    }
    
    return tokenInfo.accessToken;
  },

  clearToken() {
    sessionStorage.removeItem('token_info');
    sessionStorage.removeItem('oauth_state');
    sessionStorage.removeItem('oauth_nonce');
    sessionStorage.removeItem('auth_timestamp');
  },

  isAuthenticated() {
    return this.getToken() !== null;
  },

  logout() {
    this.clearToken();
  }
};

const ProtectedRoute = ({ children }) => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    const checkAuth = () => {
      const authenticated = AuthService.isAuthenticated();
      setIsAuthenticated(authenticated);
      setIsLoading(false);
    };
    
    checkAuth();
  }, []);

  if (isLoading) {
    return <div>Loading...</div>;
  }

  if (!isAuthenticated) {
    return (
      <div>
        <h2>Please log in</h2>
        <button onClick={() => AuthService.initiateAuth()}>Login</button>
      </div>
    );
  }

  return children;
};

const CallbackPage = ({ onSuccess }) => {
  const [error, setError] = useState(null);

  useEffect(() => {
    try {
      if (window.location.hash) {
        const tokenData = AuthService.parseCallback();
        AuthService.storeToken(tokenData);
        onSuccess();
      }
    } catch (err) {
      setError(err.message);
      setTimeout(() => {
        window.location.href = '/';
      }, 3000);
    }
  }, [onSuccess]);

  if (error) {
    return (
      <div>
        <h2>Authentication Error</h2>
        <p>{error}</p>
        <p>Redirecting to home...</p>
      </div>
    );
  }

  return <div>Processing authentication...</div>;
};

const Dashboard = () => {
  const [userData, setUserData] = useState(null);

  const fetchUserData = async () => {
    const token = AuthService.getToken();
    if (!token) return;

    try {
      const response = await fetch('https://your-api.com/user', {
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        }
      });

      if (response.ok) {
        const data = await response.json();
        setUserData(data);
      } else if (response.status === 401) {
        AuthService.clearToken();
        window.location.reload();
      }
    } catch (error) {
      console.error('Error fetching user data:', error);
    }
  };

  useEffect(() => {
    fetchUserData();
  }, []);

  const handleLogout = () => {
    AuthService.logout();
    window.location.href = '/';
  };

  return (
    <div>
      <h1>Dashboard</h1>
      {userData && (
        <div>
          <h2>Welcome, {userData.name || 'User'}</h2>
          <pre>{JSON.stringify(userData, null, 2)}</pre>
        </div>
      )}
      <button onClick={handleLogout}>Logout</button>
    </div>
  );
};

const App = () => {
  const [currentPath, setCurrentPath] = useState(window.location.pathname);

  useEffect(() => {
    const handlePopState = () => {
      setCurrentPath(window.location.pathname);
    };

    window.addEventListener('popstate', handlePopState);
    return () => window.removeEventListener('popstate', handlePopState);
  }, []);

  const navigate = (path) => {
    window.history.pushState({}, '', path);
    setCurrentPath(path);
  };

  if (currentPath === '/callback') {
    return <CallbackPage onSuccess={() => navigate('/')} />;
  }

  return (
    <div style={{ padding: '20px', fontFamily: 'Arial, sans-serif' }}>
      <ProtectedRoute>
        <Dashboard />
      </ProtectedRoute>
    </div>
  );
};

const container = document.getElementById('root');
const root = createRoot(container);
root.render(<App />);